class Solution:
    def maxGCDScore(self, nums: List[int], k: int) -> int:
        d_set = set()
        for x in nums:
            d_set.add(x)
            d_set.add(2 * x)
        d_list = sorted(d_set, reverse=True)
        max_score = 0
        n = len(nums)
        for d in d_list:
            if d * n <= max_score:
                break
            cost = []
            for x in nums:
                if x % d == 0:
                    cost.append(0)
                elif (2 * x) % d == 0:
                    cost.append(1)
                else:
                    cost.append(float('inf'))
            left = 0
            current_sum = 0
            current_max = 0
            for right in range(len(cost)):
                if cost[right] == float('inf'):
                    left = right + 1
                    current_sum = 0
                    continue
                current_sum += cost[right]
                while current_sum > k:
                    current_sum -= cost[left]
                    left += 1
                window_length = right - left + 1
                if window_length > current_max:
                    current_max = window_length
            score = current_max * d
            if score > max_score:
                max_score = score
        return max_score

